authRoutes.get("/me", async (c) => {
  try {
    const cookieHeader = c.req.header("cookie");
    let sid = getCookie(c, "sid");
    if (!sid && cookieHeader) {
      const cookies = cookieHeader.split(";").map((c2) => c2.trim());
      for (const cookie of cookies) {
        const [name, value] = cookie.split("=");
        if (name.trim() === "sid" && value) {
          sid = value.trim();
          break;
        }
      }
    }
    if (!sid)
      return c.json({ loggedIn: false });
    const result = await c.env.DB.prepare(`
      select 
        s.id as session_id,
        s.user_id,
        s.expires_at,
        u.id,
        u.name,
        u.email,
        u.role
      from sessions s
      left join users u on u.id = s.user_id
      where s.id = ? and s.expires_at > ?
    `).bind(sid, Date.now()).first();
    if (!result || !result.user_id)
      return c.json({ loggedIn: false });
    const { getUserPosition: getUserPosition3 } = await Promise.resolve().then(() => (init_db(), db_exports));
    const { getRoleByPositionCode: getRoleByPositionCode2 } = await Promise.resolve().then(() => (init_db(), db_exports));
    const position = await getUserPosition3(c.env.DB, result.id);
    if (!position) {
      return c.json({ loggedIn: false, error: "employee record not found" });
    }
    const userRole = getRoleByPositionCode2(position.code);
    return c.json({
      loggedIn: true,
      id: result.id,
      name: result.name,
      email: result.email,
      role: userRole,
      position: {
        id: position.id,
        code: position.code,
        name: position.name,
        level: position.level,
        scope: position.scope,
        canViewReports: position.code === "hq_admin" || position.code === "hq_finance" || position.permissions?.reports === true
      }
    });
  } catch (error3) {
    console.error("[GET /me] Error:", error3);
    return c.json({ loggedIn: false });
  }
});
