function detectDepartmentType(code, name) {
  const key = (code || name || "").toLowerCase();
  if (key.includes("hr") || key.includes("\u4EBA\u4E8B"))
    return "HR";
  if (key.includes("finance") || key.includes("\u8D22\u52A1"))
    return "FINANCE";
  if (key.includes("admin") || key.includes("\u884C\u653F"))
    return "ADMIN";
  if (key.includes("tech") || key.includes("\u6280\u672F") || key.includes("\u5F00\u53D1"))
    return "TECH";
  return "OTHER";
}
