async function refreshDocStatus(db, docId) {
  const doc = await db.prepare("select amount_cents from ar_ap_docs where id=?").bind(docId).first();
  if (!doc)
    return;
  const s2 = await db.prepare("select coalesce(sum(settle_amount_cents),0) as s from settlements where doc_id=?").bind(docId).first();
  const total = s2?.s ?? 0;
  const status = total <= 0 ? "open" : total < (doc.amount_cents ?? 0) ? "partially_settled" : "settled";
  await db.prepare("update ar_ap_docs set status=? where id=?").bind(status, docId).run();
}
