cashFlowReportsRoutes.get("/site-growth", validateQuery(dateRangeQuerySchema), async (c) => {
  if (!canRead(c))
    throw Errors.FORBIDDEN();
  if (!await canViewReports(c))
    throw Errors.FORBIDDEN("\u53EA\u6709\u603B\u90E8\u4EBA\u5458\u53EF\u4EE5\u67E5\u770B\u62A5\u8868");
  const query = getValidatedQuery(c);
  const start = query.start;
  const end = query.end;
  const startDate = /* @__PURE__ */ new Date(start + "T00:00:00Z");
  const endDate = /* @__PURE__ */ new Date(end + "T00:00:00Z");
  const days = Math.max(1, Math.round((endDate.getTime() - startDate.getTime()) / 864e5) + 1);
  const prevEnd = new Date(startDate.getTime() - 864e5);
  const prevStart = new Date(prevEnd.getTime() - (days - 1) * 864e5);
  const prevStartStr = prevStart.toISOString().slice(0, 10);
  const prevEndStr = prevEnd.toISOString().slice(0, 10);
  const role = c.get("userRole");
  const userId = c.get("userId");
  let curSql = `
    select s.id as site_id, s.name as site_name,
      coalesce(sum(case when f.type='income' then f.amount_cents end),0) as income_cents,
      coalesce(sum(case when f.type='expense' then f.amount_cents end),0) as expense_cents
    from sites s
    left join cash_flows f on f.site_id=s.id and f.biz_date>=? and f.biz_date<=?
  `;
  let curBinds = [start, end];
  let prevSql = `
    select s.id as site_id,
      coalesce(sum(case when f.type='income' then f.amount_cents end),0) as income_cents
    from sites s
    left join cash_flows f on f.site_id=s.id and f.biz_date>=? and f.biz_date<=?
  `;
  let prevBinds = [prevStartStr, prevEndStr];
  if (role !== "manager" && role !== "finance" && userId) {
    const deptId = await getUserDepartmentId(c.env.DB, userId);
    if (deptId) {
      curSql += " where s.department_id=?";
      curBinds.push(deptId);
      prevSql += " where s.department_id=?";
      prevBinds.push(deptId);
    }
  }
  curSql += " group by s.id, s.name";
  prevSql += " group by s.id";
  const cur = await c.env.DB.prepare(curSql).bind(...curBinds).all();
  const prev = await c.env.DB.prepare(prevSql).bind(...prevBinds).all();
  const prevMap = new Map((prev.results ?? []).map((r2) => [r2.site_id, r2.income_cents || 0]));
  const rows = (cur.results ?? []).map((r2) => {
    const net = (r2.income_cents || 0) - (r2.expense_cents || 0);
    const prevIncome = prevMap.get(r2.site_id) || 0;
    const growth_rate = prevIncome === 0 ? r2.income_cents > 0 ? 1 : 0 : (r2.income_cents - prevIncome) / prevIncome;
    return { ...r2, net_cents: net, prev_income_cents: prevIncome, growth_rate };
  });
  return c.json({ rows, prev_range: { start: prevStartStr, end: prevEndStr } });
});

